def verify_signature(payload: bytes, signature: str, secret: str, algorithm: str = "sha256") -> bool:
    """Verify HMAC signature from the payment provider."""
    if not secret:
        logging.warning("WEBHOOK_SECRET is not configured - signature verification skipped")
        return False

    if not signature:
        return False

    # Support common signature formats: "sha256=<hex>" or just "<hex>"
    if "=" in signature:
        algo_prefix, sig_value = signature.split("=", 1)
    else:
        sig_value = signature
        algo_prefix = algorithm

    if algo_prefix not in ("sha256", "sha512"):
        logging.warning(f"Unsupported signature algorithm: {algo_prefix}")
        return False

    hash_func = hashlib.sha256 if algo_prefix == "sha256" else hashlib.sha512
    expected = hmac.new(secret.encode("utf-8"), payload, hash_func).hexdigest()

    return hmac.compare_digest(expected, sig_value)


def check_ip_allowlist(client_ip: str) -> bool:
    """Check if the client IP is in the allowlist."""
    if not ALLOWED_IPS or ALLOWED_IPS == [""]:
        # If no allowlist configured, log warning but allow (defense in depth via other checks)
        logging.warning("No IP allowlist configured. Consider setting ALLOWED_IPS.")
        return True

    return client_ip in ALLOWED_IPS


def check_rate_limit(client_ip: str) -> bool:
    """Simple sliding window rate limiter."""
    now = time.time()
    window_start = now - RATE_LIMIT_WINDOW

    if client_ip not in _rate_limit_store:
        _rate_limit_store[client_ip] = []

    # Remove old entries
    _rate_limit_store[client_ip] = [
        t for t in _rate_limit_store[client_ip] if t > window_start
    ]

    if len(_rate_limit_store[client_ip]) >= RATE_LIMIT_MAX_REQUESTS:
        return False

    _rate_limit_store[client_ip].append(now)
    return True


def check_replay_attack(event_id: str, timestamp: str) -> bool:
    """Prevent replay attacks by checking event ID uniqueness and timestamp freshness."""
