    # Check for duplicate event ID
    if event_id and event_id in _processed_event_ids:
        logging.warning(f"Duplicate event ID detected: {event_id}")
        return False

    # Check timestamp freshness
    if timestamp:
        try:
            event_time = float(timestamp)
            if abs(now - event_time) > REPLAY_ATTACK_TOLERANCE_SECONDS:
                logging.warning(f"Stale webhook timestamp: {timestamp}")
                return False
        except (ValueError, TypeError):
            try:
                event_dt = datetime.fromisoformat(timestamp.replace("Z", "+00:00"))
                event_time = event_dt.timestamp()
                if abs(now - event_time) > REPLAY_ATTACK_TOLERANCE_SECONDS:
                    logging.warning(f"Stale webhook timestamp: {timestamp}")
                    return False
            except (ValueError, TypeError):
                logging.warning(f"Unable to parse timestamp: {timestamp}")
                return False

    # Record the event ID
